const results = [];

// This loop is mandatory to handle 5 bounces at once instead of just 1
for (const item of $input.all()) {
  const json = item.json;
  const payload = json.payload || {};
  let fullBody = "";

  // Recursive extractor to dig through Google's nested multipart/report formats
  function extractData(part) {
    if (part.body && part.body.data) {
      fullBody += Buffer.from(part.body.data, 'base64').toString('utf8') + "\n";
    }
    if (part.parts && Array.isArray(part.parts)) {
      for (const p of part.parts) {
        extractData(p);
      }
    }
  }

  extractData(payload);

  if (!fullBody && json.snippet) { 
    fullBody += json.snippet; 
  }

  const rawFrom = json.headers?.from || json.From || "";
  const subject = json.headers?.subject || json.Subject || "";

  const isBounce = rawFrom.toLowerCase().includes("mailer-daemon@googlemail.com");

  let targetEmail = "";
  let cleanBody = fullBody;

  if (isBounce) {
    // Regex based exactly on your screenshots
    const bounceMatch = fullBody.match(/(?:Votre message n'est pas parvenu à|Your message wasn't delivered to)\s*([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/i);

    if (bounceMatch && bounceMatch[1]) {
      targetEmail = bounceMatch[1].trim();
    } else {
      const fallbackMatch = fullBody.match(/([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/);
      targetEmail = fallbackMatch ? fallbackMatch[1].trim() : "unknown_bounce";
    }
  } else {
    const emailMatch = rawFrom.match(/<([^>]+)>/);
    targetEmail = emailMatch ? emailMatch[1] : rawFrom.trim();

    const replyMarkers = [
      /(?:\s|^)Le\s+.*?\s+à\s+.*?\s+a\s+écrit\s*:/i,
      /(?:\s|^)On\s+.*?\s+wrote\s*:/i,
      /(?:\s|^)---\s*Original\s+Message\s*---/i,
      /(?:\s|^)________________________________/i,
      /\n\s*>/ 
    ];

    for (const marker of replyMarkers) {
      const index = cleanBody.search(marker);
      if (index !== -1) cleanBody = cleanBody.substring(0, index);
    }
  }

  let date_iso = "";
  if (json.internalDate) {
    const d = new Date(Number(json.internalDate));
    if (!isNaN(d)) date_iso = d.toISOString().slice(0, 19); 
  }

  results.push({
    json: {
      isBounce: isBounce,
      email: targetEmail,
      subject: subject,
      emailBody: cleanBody.trim(),
      repliedAt: date_iso
    }
  });
}

return results;
